import numpy as np
from scipy.linalg import solve

def gaussian_kernel(x, x_q, tau):
 return np.exp(-((x - x_q) ** 2) / (2 * tau ** 2))

def locally_weighted_regression(X, y, x_q, tau):
 weights = gaussian_kernel(X, x_q, tau)
 X_weighted = np.vstack([np.ones_like(X), X]).T * weights[:, np.newaxis]
 y_weighted = y * weights
 theta = solve(X_weighted.T @ X_weighted, X_weighted.T @ y_weighted)
 return theta[0] + theta[1] * x_q

